package com.fasterxml.jackson.dataformat.xml.deser.steps;

import com.fasterxml.jackson.annotation.JsonProperty;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlProperty;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlText;
import io.cucumber.java.en.*;
import org.junit.Assert;

import java.io.IOException;

import com.fasterxml.jackson.dataformat.xml.XmlMapper;

import static org.junit.Assert.*;

public class StepDefs {

    private String xmlInput;
    private Object targetObject;
    private WindSpeed windSpeed;
    private Class<?> targetClass;
    private String className;
    private Object deserializedObject;

    @Given("an XML input {string}")
    public void an_xml_input(String xmlString) {
        this.xmlInput = xmlString;
    }

    @Given("a target class {string} with:")
    public void a_target_class_with(String className, io.cucumber.datatable.DataTable table) throws ClassNotFoundException {
        this.className = className;
        if ("WindSpeed".equals(className)) {
            // The class will be defined below
        }
    }

    @And("the {string} class has a field {string}")
    public void the_class_has_a_field(String className, String fieldName) {
        // This is handled in the context of the test
    }

    @When("the XML is deserialized into the {string} object")
    public void the_xml_is_deserialized_into_the_object(String className) throws IOException {
        XmlMapper xmlMapper = new XmlMapper();
        if ("WindSpeed".equals(className)) {
            this.deserializedObject = xmlMapper.readValue(xmlInput, WindSpeed.class);
        }
    }

    @Then("the field {string} should be equal to {int}")
    public void the_field_should_be_equal_to(String fieldName, Integer expectedValue) {
        if ("value".equals(fieldName)) {
            assertEquals(expectedValue.intValue(), this.windSpeed != null ? this.windSpeed.value : ((WindSpeed)deserializedObject).value);
        }
    }

    @Then("the field {string} should not be null")
    public void the_field_should_not_be_null(String fieldName) {
        if ("radius".equals(fieldName)) {
            assertNotNull(this.windSpeed != null ? this.windSpeed.radius : ((WindSpeed)deserializedObject).radius);
        }
    }

    @And("the nested field {string} should be equal to {int}")
    public void the_nested_field_should_be_equal_to(String fieldName, Integer expectedValue) {
        if ("radius.value".equals(fieldName)) {
            WindSpeed ws = (WindSpeed)deserializedObject;
            assertNotNull(ws.radius);
            assertEquals(expectedValue.intValue(), ws.radius.value);
        }
    }

    public static class WindSpeed {
        @JacksonXmlText
        public int value;

        @JacksonXmlProperty
        public Radius radius;
    }

    public static class Radius {
        public int value;
    }
}
